import { STATUS_COLORS } from "../data/odontogramaConstants";
import { getWholeAction } from "../utils/odontogramaHelpers";

/*
 * Las siluetas se encuentran incrustadas como PNG transparentes dentro
 * del propio componente. Fueron aisladas de la referencia visual para
 * conservar exactamente su anatomía y evitar archivos externos.
 */
const TOOTH_SPRITES = {
  18: "data:image/png;base64,",
  17: "data:image/png;base64,",
  16: "data:image/png;base64,",
  15: "data:image/png;base64,",
  14: "data:image/png;base64,",
  13: "data:image/png;base64,",
  12: "data:image/png;base64,",
  11: "data:image/png;base64,",
  21: "data:image/png;base64,",
  22: "data:image/png;base64,",
  23: "data:image/png;base64,",
  24: "data:image/png;base64,",
  25: "data:image/png;base64,",
  26: "data:image/png;base64,",
  27: "data:image/png;base64,",
  28: "data:image/png;base64,",
  31: "data:image/png;base64,",
  32: "data:image/png;base64,",
  33: "data:image/png;base64,",
  34: "data:image/png;base64,",
  35: "data:image/png;base64,",
  36: "data:image/png;base64,",
  37: "data:image/png;base64,",
  38: "data:image/png;base64,",
  41: "data:image/png;base64,",
  42: "data:image/png;base64,",
  43: "data:image/png;base64,",
  44: "data:image/png;base64,",
  45: "data:image/png;base64,",
  46: "data:image/png;base64,",
  47: "data:image/png;base64,",
  48: "data:image/png;base64,",
};

function toothPosition(num) {
  return Math.abs(Number(num)) % 10;
}

function resolveSpriteKey(num) {
  const piece = Number(num);

  const temporaryAliases = {
    51: 11,
    52: 12,
    53: 13,
    54: 16,
    55: 17,
    61: 21,
    62: 22,
    63: 23,
    64: 26,
    65: 27,
    71: 31,
    72: 32,
    73: 33,
    74: 36,
    75: 37,
    81: 41,
    82: 42,
    83: 43,
    84: 46,
    85: 47,
  };

  return temporaryAliases[piece] || piece;
}

export default function ToothSVG({
  num,
  upper,
  tooth,
  onContextMenu,
  onClick,
  small,
}) {
  const w = small ? 34 : 44;
  const h = small ? 72 : 90;
  const marks = tooth?.marks || [];
  const position = toothPosition(num);
  const isTemporary = Number(num) >= 50;
  const isMolar = position >= 6 || (isTemporary && position >= 4);
  const sprite = TOOTH_SPRITES[resolveSpriteKey(num)];

  const ausente = getWholeAction(marks, ["ausente"]);
  const implante = getWholeAction(marks, ["implante"]);
  const endodoncia = getWholeAction(marks, ["endodoncia"]);
  const restoRadicular = getWholeAction(marks, ["resto_radicular"]);
  const exodoncia = getWholeAction(marks, ["indicada_exodoncia"]);
  const brackets = getWholeAction(marks, ["brackets"]);
  const sellante = getWholeAction(marks, ["sellante"]);

  const corona =
    getWholeAction(marks, [
      "corona_metal_porcelana",
      "corona_libre_metal",
      "corona_acero_cromado",
    ]) || null;

  const fractureMarks = marks.filter(
    (mark) => mark.actionId === "fractura_coronal",
  );

  const baseStroke = "#49628f";
  const filterBaseId = `tooth-base-${num}`;
  const filterRootId = `tooth-root-${num}`;
  const filterCrownId = `tooth-crown-${num}`;
  const rootClipId = `tooth-root-clip-${num}`;
  const crownClipId = `tooth-crown-clip-${num}`;
  const orientation = upper ? undefined : "translate(0 96) scale(1 -1)";
  const rootColor = endodoncia?.color || restoRadicular?.color || null;

  return (
    <svg
      width={w}
      height={h}
      viewBox="0 0 48 96"
      role="img"
      aria-label={`Pieza dental ${num}`}
      onContextMenu={(event) => onContextMenu?.(event, num)}
      onClick={(event) => {
        event.stopPropagation();
        onClick?.(event, num);
      }}
      className="cursor-pointer block select-none"
      style={{ overflow: "visible" }}
    >
      <defs>
        <filter id={filterBaseId} colorInterpolationFilters="sRGB">
          <feFlood floodColor={baseStroke} result="paint" />
          <feComposite in="paint" in2="SourceAlpha" operator="in" />
        </filter>

        <filter id={filterRootId} colorInterpolationFilters="sRGB">
          <feFlood floodColor={rootColor || baseStroke} result="paint" />
          <feComposite in="paint" in2="SourceAlpha" operator="in" />
        </filter>

        <filter id={filterCrownId} colorInterpolationFilters="sRGB">
          <feFlood floodColor={corona?.color || baseStroke} result="paint" />
          <feComposite in="paint" in2="SourceAlpha" operator="in" />
        </filter>

        <clipPath id={rootClipId}>
          <rect x="0" y="35" width="48" height="61" />
        </clipPath>

        <clipPath id={crownClipId}>
          <rect x="0" y="0" width="48" height="39" />
        </clipPath>
      </defs>

      <g transform={orientation}>
        {!ausente && !implante && sprite && (
          <>
            <image
              href={sprite}
              x="1"
              y="1"
              width="46"
              height="94"
              preserveAspectRatio="xMidYMid meet"
              filter={`url(#${filterBaseId})`}
              pointerEvents="none"
            />

            {rootColor && (
              <image
                href={sprite}
                x="1"
                y="1"
                width="46"
                height="94"
                preserveAspectRatio="xMidYMid meet"
                clipPath={`url(#${rootClipId})`}
                filter={`url(#${filterRootId})`}
                pointerEvents="none"
              />
            )}

            {corona && (
              <>
                <path
                  d={
                    isMolar
                      ? "M7 11 Q9 5 17 5 H31 Q39 5 41 11 L40 34 Q36 39 24 39 Q12 39 8 34 Z"
                      : position === 3
                        ? "M13 28 Q13 13 24 5 Q35 13 35 28 Q34 38 24 39 Q14 38 13 28 Z"
                        : "M13 8 Q24 4 35 8 L35 29 Q34 38 24 39 Q14 38 13 29 Z"
                  }
                  fill={corona.color}
                  fillOpacity="0.1"
                  stroke={corona.color}
                  strokeWidth="1.2"
                  strokeDasharray="2.6 1.8"
                  strokeLinejoin="round"
                  pointerEvents="none"
                />
                <image
                  href={sprite}
                  x="1"
                  y="1"
                  width="46"
                  height="94"
                  preserveAspectRatio="xMidYMid meet"
                  clipPath={`url(#${crownClipId})`}
                  filter={`url(#${filterCrownId})`}
                  pointerEvents="none"
                />
              </>
            )}
          </>
        )}

        {implante && (
          <>
            <path
              d="M14 29 Q15 19 24 16 Q33 19 34 29 L32 38 H16 Z"
              fill="#f8fafc"
              stroke={implante.color}
              strokeWidth="1.6"
              strokeLinejoin="round"
            />
            <path
              d="M18 38 L20 82 Q24 89 28 82 L30 38 Z"
              fill="none"
              stroke={implante.color}
              strokeWidth="1.8"
              strokeLinejoin="round"
            />
            {[47, 56, 65, 74].map((y) => (
              <line
                key={y}
                x1="19"
                y1={y}
                x2="29"
                y2={y}
                stroke={implante.color}
                strokeWidth="1"
              />
            ))}
          </>
        )}

        {sellante && !ausente && !implante && (
          <text
            x="24"
            y="25"
            textAnchor="middle"
            fontSize="10"
            fontWeight="800"
            fill={sellante.color}
            pointerEvents="none"
          >
            S
          </text>
        )}

        {brackets && !ausente && !implante && (
          <>
            <line
              x1="9"
              y1="28"
              x2="39"
              y2="28"
              stroke={brackets.color}
              strokeWidth="1.2"
            />
            <rect
              x="18"
              y="23"
              width="12"
              height="10"
              rx="2"
              fill="#ffffff"
              stroke={brackets.color}
              strokeWidth="1.4"
            />
            <line
              x1="24"
              y1="23"
              x2="24"
              y2="33"
              stroke={brackets.color}
              strokeWidth="1"
            />
          </>
        )}

        {fractureMarks.length > 0 && !ausente && !implante && (
          <path
            d="M14 11 L19 16 L16 20 L23 24 L20 29 L29 34"
            fill="none"
            stroke={STATUS_COLORS.rojo}
            strokeWidth="1.9"
            strokeLinecap="round"
            strokeLinejoin="round"
            pointerEvents="none"
          />
        )}

        {ausente && (
          <>
            <line
              x1="10"
              y1="10"
              x2="38"
              y2="86"
              stroke={ausente.color}
              strokeWidth="2.8"
              strokeLinecap="round"
            />
            <line
              x1="38"
              y1="10"
              x2="10"
              y2="86"
              stroke={ausente.color}
              strokeWidth="2.8"
              strokeLinecap="round"
            />
          </>
        )}

        {exodoncia && (
          <line
            x1="7"
            y1="7"
            x2="41"
            y2="89"
            stroke={exodoncia.color}
            strokeWidth="2.4"
            strokeLinecap="round"
            pointerEvents="none"
          />
        )}
      </g>
    </svg>
  );
}